def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    import numpy as np

    new_matrix = time_matrix.copy()
    C = np.zeros((n, m))
    for i, job in enumerate(current_sequence):
        for j in range(m):
            if i == 0 and j == 0:
                C[i, j] = time_matrix[job, j]
            elif i == 0:
                C[i, j] = C[i, j-1] + time_matrix[job, j]
            elif j == 0:
                C[i, j] = C[i-1, j] + time_matrix[job, j]
            else:
                C[i, j] = max(C[i-1, j], C[i, j-1]) + time_matrix[job, j]

    # Compute completion time variance per machine (normalized)
    machine_var = np.zeros(m)
    for j in range(m):
        col = C[:, j]
        machine_var[j] = np.var(col) / (np.mean(col) + 1e-8)

    # Select machines with variance above median
    median_var = np.median(machine_var)
    high_var_machines = np.where(machine_var > median_var)[0]

    # Amplify processing times on high-variance machines by random factor (1.1-1.5)
    if len(high_var_machines) > 0:
        for j in high_var_machines:
            factor = 1.1 + 0.4 * np.random.random()
            new_matrix[:, j] *= factor

    # Compute critical path contributions per job
    job_critical_score = np.zeros(n)
    for i, job in enumerate(current_sequence):
        for j in range(m):
            if i > 0 and j > 0:
                slack = C[i, j] - time_matrix[job, j]
                prev = max(C[i-1, j], C[i, j-1])
                if abs(slack - prev) < 1e-6:
                    job_critical_score[job] += time_matrix[job, j]

    # Select top 2–5 jobs by critical score, preferring diversity
    sorted_jobs = np.argsort(-job_critical_score)
    perturb_jobs = []
    seen = set()
    for idx in sorted_jobs:
        if len(perturb_jobs) >= 5:
            break
        if idx not in seen:
            perturb_jobs.append(int(idx))
            seen.add(idx)
    if len(perturb_jobs) < 2:
        for i in range(n):
            if len(perturb_jobs) >= 2:
                break
            if i not in seen:
                perturb_jobs.append(i)
    perturb_jobs = perturb_jobs[:5]

    return new_matrix, perturb_jobs

def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    new_matrix = time_matrix.copy()

    # Compute completion times
    C = np.zeros((n, m))
    for i, job in enumerate(current_sequence):
        if i == 0:
            C[i, 0] = new_matrix[job, 0]
        else:
            C[i, 0] = C[i-1, 0] + new_matrix[job, 0]
        for k in range(1, m):
            C[i, k] = max(C[i, k-1], C[i-1, k]) + new_matrix[job, k]

    # Calculate idle time caused by each job (cumulative across machines)
    idle_cost = np.zeros(n)
    for idx, job in enumerate(current_sequence):
        for k in range(m):
            if idx == 0:
                idle_before = 0
            else:
                idle_before = max(0, C[idx, k] - new_matrix[job, k] - C[idx-1, k])
            if idx == n-1:
                idle_after = 0
            else:
                idle_after = max(0, C[idx+1, k] - C[idx, k])
            idle_cost[job] += idle_before + idle_after

    # Select jobs with highest idle cost (most disruptive)
    critical_indices = np.argsort(idle_cost)[-min(5, n):][::-1]

    # Reduce processing times for critical jobs to encourage different sequences
    reduction_factor = 0.7
    for job in critical_indices:
        new_matrix[job, :] *= reduction_factor

    perturb_jobs = critical_indices.tolist()
    return new_matrix, perturb_jobs
